const DOMAIN_MAP = new Map<string, string>();

// Build domain → brand key map
for (const brand of BRANDS) {
  // Map common domain patterns
  switch (brand.key) {
    case 'youtube':
      DOMAIN_MAP.set('youtube.com', brand.key);
      DOMAIN_MAP.set('youtu.be', brand.key);
      break;
    case 'twitter':
      DOMAIN_MAP.set('twitter.com', brand.key);
      DOMAIN_MAP.set('x.com', brand.key);
      break;
    case 'instagram':
      DOMAIN_MAP.set('instagram.com', brand.key);
      break;
    case 'tiktok':
      DOMAIN_MAP.set('tiktok.com', brand.key);
      break;
    case 'spotify':
      DOMAIN_MAP.set('spotify.com', brand.key);
      DOMAIN_MAP.set('open.spotify.com', brand.key);
      break;
    case 'linkedin':
      DOMAIN_MAP.set('linkedin.com', brand.key);
      break;
    case 'github':
      DOMAIN_MAP.set('github.com', brand.key);
      break;
    case 'twitch':
      DOMAIN_MAP.set('twitch.tv', brand.key);
      break;
    case 'discord':
      DOMAIN_MAP.set('discord.gg', brand.key);
      DOMAIN_MAP.set('discord.com', brand.key);
      break;
    case 'facebook':
      DOMAIN_MAP.set('facebook.com', brand.key);
      DOMAIN_MAP.set('fb.com', brand.key);
      DOMAIN_MAP.set('fb.me', brand.key);
      break;
    case 'pinterest':
      DOMAIN_MAP.set('pinterest.com', brand.key);
      DOMAIN_MAP.set('pin.it', brand.key);
      break;
    case 'snapchat':
      DOMAIN_MAP.set('snapchat.com', brand.key);
      break;
    case 'whatsapp':
      DOMAIN_MAP.set('whatsapp.com', brand.key);
      DOMAIN_MAP.set('wa.me', brand.key);
      break;
    case 'telegram':
      DOMAIN_MAP.set('telegram.org', brand.key);
      DOMAIN_MAP.set('t.me', brand.key);
      break;
    case 'amazon':
      DOMAIN_MAP.set('amazon.com', brand.key);
      DOMAIN_MAP.set('amzn.to', brand.key);
      break;
    case 'apple-music':
      DOMAIN_MAP.set('music.apple.com', brand.key);
      break;
    case 'soundcloud':
      DOMAIN_MAP.set('soundcloud.com', brand.key);
      break;
    case 'patreon':
      DOMAIN_MAP.set('patreon.com', brand.key);
      break;
    case 'threads':
      DOMAIN_MAP.set('threads.net', brand.key);
      break;
    case 'substack':
      DOMAIN_MAP.set('substack.com', brand.key);
      break;
    case 'cash-app':
      DOMAIN_MAP.set('cash.app', brand.key);
      break;
    case 'venmo':
      DOMAIN_MAP.set('venmo.com', brand.key);
      break;
    case 'ko-fi':
      DOMAIN_MAP.set('ko-fi.com', brand.key);
      break;
  }
}

/**
 * Detect brand from a URL string.
 * Returns null if no known brand is matched.
 */
export function detectBrand(url: string): BrandInfo | null {
  try {
    const hostname = new URL(url).hostname.replace(/^www\./, '').toLowerCase();

    // Exact match first
    const exactKey = DOMAIN_MAP.get(hostname);
    if (exactKey) {
      return BRANDS.find((b) => b.key === exactKey) ?? null;
    }

    // Subdomain match (e.g. open.spotify.com → spotify.com)
    for (const [domain, key] of DOMAIN_MAP) {
      if (hostname.endsWith('.' + domain) || hostname === domain) {
        return BRANDS.find((b) => b.key === key) ?? null;
      }
    }

    // Check if hostname contains a brand name as fallback
    for (const brand of BRANDS) {
      if (hostname.includes(brand.key.replace('-', ''))) {
        return brand;
      }
    }
  } catch {
    // Invalid URL — return null
  }
  return null;
}

/**
 * Auto-detect and return the brand key for a URL (or null).
 * Used to populate the icon field on creator_links.
 */
export function detectBrandKey(url: string): string | null {
  return detectBrand(url)?.key ?? null;
}

/**
 * Get brand info by key.
 */
export function getBrandByKey(key: string): BrandInfo | null {
  return BRANDS.find((b) => b.key === key) ?? null;
}

/**
 * Get all supported brands (for picker UI, etc.)
 */
export function getAllBrands(): BrandInfo[] {
  return [...BRANDS];
}
